let reviewCount = 0;
first3Products.forEach((prod) => {
  sampleReviews.forEach((rev, index) => {
    db.reviews.updateOne(
      { productId: prod._id.toString(), userId: `user-${index + 1}` },
      {
        $set: {
          userName: rev.userName,
          rating: rev.rating,
          title: rev.title,
          comment: rev.comment,
          verified: true,
          createdAt: new Date()
        }
      },
      { upsert: true }
    );
    reviewCount++;
  });
});

print(`✓ ${reviewCount} reviews upserted for top 3 products.`);
print("✓ catalog_db seeding complete.");
